const raw = $json.text || $json.content || $json.response || '';
const prev = $('Extraer sentimiento').first().json;
let summary = 'No se pudo generar resumen.';
let reasons = [];
try {
  const cleaned = raw.trim().replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  summary = parsed.summary || summary;
  reasons = Array.isArray(parsed.reasons) ? parsed.reasons : [];
} catch(e) {
  summary = raw.substring(0, 300);
  reasons = ['No se pudieron extraer razones estructuradas.'];
}
const reasonsHtml = reasons.map(r => `<li>${r}</li>`).join('');
const reasonsText = reasons.map((r,i) => `${i+1}. ${r}`).join('\n');
return [{ json: { ...prev, summary, reasons, reasonsHtml, reasonsText, emailSubject: `Tweet Negativo [${prev.topic}] - ${prev.timestamp.substring(0,10)}` } }];

const raw = $json.text || $json.content || $json.response || '';
const prev = $('Preparar Datos Negativos').first().json;
let draft = 'No se pudo generar respuesta sugerida.';
try {
  const cleaned = raw.trim().replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  draft = parsed.draft || draft;
} catch(e) {
  draft = raw.substring(0, 280);
}
return [{ json: { ...prev, draft } }];

