const tweet = $json.tweet || '';
if (!tweet) throw new Error('Campo tweet vacio o ausente en la fila.');
return [{ json: { tweet, retry_count: 0, timestamp: new Date().toISOString() } }];

const raw = $json.text || $json.content || $json.response || '';
const tweet = $('Inicio').first().json.tweet || '';
const timestamp = $('Inicio').first().json.timestamp || '';
const retry_count = $('Inicio').first().json.retry_count || 0;
let sentiment = 'UNKNOWN';
let topic = 'otro';
try {
  const cleaned = raw.trim().replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  sentiment = (parsed.sentiment || 'UNKNOWN').toUpperCase().trim();
  topic = (parsed.topic || 'otro').toLowerCase().trim();
} catch(e) {
  const up = raw.toUpperCase();
  if (up.includes('NEGATIVO')) sentiment = 'NEGATIVO';
  else if (up.includes('POSITIVO')) sentiment = 'POSITIVO';
  else if (up.includes('NEUTRAL')) sentiment = 'NEUTRAL';
}
const valid = ['NEGATIVO','POSITIVO','NEUTRAL'];
const needs_retry = !valid.includes(sentiment) && retry_count < 3;
return [{ json: { tweet, sentiment, topic, raw_response: raw, timestamp, retry_count, needs_retry } }];

const data = $json;
const retry_count = (data.retry_count || 0) + 1;
console.log(`[REINTENTO ${retry_count}/3] Tweet: ${data.tweet.substring(0,60)}`);
return [{ json: { tweet: data.tweet, retry_count, timestamp: data.timestamp } }];
